import React, { useState, useEffect, useMemo } from 'react';

// Иконки SVG (inline для надежности)
const Icon = ({ name }) => {
  const icons = {
    telegram: (
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm4.64 6.8c-.15 1.58-.8 5.42-1.13 7.19-.14.75-.42 1-.68 1.03-.58.05-1.02-.38-1.58-.75-.88-.58-1.38-.94-2.23-1.5-.99-.65-.35-1.01.22-1.59.15-.15 2.71-2.48 2.76-2.69.01-.03.01-.14-.07-.2-.08-.06-.19-.04-.27-.02-.11.02-1.93 1.23-5.46 3.62-.51.35-.98.53-1.39.52-.46-.01-1.33-.26-1.98-.48-.8-.27-1.43-.42-1.37-.89.03-.25.38-.51 1.03-.78 4.04-1.76 6.74-2.92 8.09-3.48 3.85-1.6 4.64-1.88 5.17-1.89.11 0 .37.03.54.17.14.12.18.28.2.45-.02.07-.02.13-.03.19z"/>
    ),
    phone: (
      <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/>
    )
  };

  return (
    <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor">
      {icons[name]}
    </svg>
  );
};

const App = () => {
  const [filter, setFilter] = useState('Все');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showArchive, setShowArchive] = useState(false);

  const categories = ['Все', 'Айдентика', 'Логотипы', 'Веб-дизайн', 'Печатная графика'];

  const projects = useMemo(() => ({
    featured: [
      { id: 'f1', title: "Проект айдентики", cat: "Айдентика", year: 2025, img: "https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&q=80&w=800" },
      { id: 'f2', title: "Веб-интерфейс", cat: "Веб-дизайн", year: 2025, img: "https://images.unsplash.com/photo-1551288049-bbbda5366392?auto=format&fit=crop&q=80&w=800" },
      { id: 'f3', title: "Логотип и стиль", cat: "Логотипы", year: 2025, img: "https://images.unsplash.com/photo-1572044162444-ad60f128bde2?auto=format&fit=crop&q=80&w=800" },
    ],
    archive: [
      { id: 'a1', title: "Учебный логотип", cat: "Логотипы", year: 2024, img: "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?auto=format&fit=crop&q=80&w=800" },
      { id: 'a2', title: "Графическая работа", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1561070791-2526d30994b5?auto=format&fit=crop&q=80&w=800" },
      { id: 'a3', title: "Макет полиграфии", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1586075010923-2dd4570fb338?auto=format&fit=crop&q=80&w=800" },
      { id: 'a4', title: "Первый лендинг", cat: "Веб-дизайн", year: 2024, img: "https://images.unsplash.com/photo-1547658719-da2b51169166?auto=format&fit=crop&q=80&w=800" },
    ]
  }), []);

  const filterFn = (p) => filter === 'Все' || p.cat === filter;
  const filteredFeatured = projects.featured.filter(filterFn);
  const filteredArchive = projects.archive.filter(filterFn);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) {
      const offset = 140; 
      window.scrollTo({
        top: el.offsetTop - offset,
        behavior: 'smooth'
      });
    }
  };

  return (
    <div className="min-h-screen bg-[#0d0d0f] text-[#e0e0e6] font-sans selection:bg-[#ffb3d9] selection:text-[#2d1b24] overflow-x-hidden">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&display=swap');

        body { 
          margin: 0;
          font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
          background-color: #0d0d0f;
          -webkit-font-smoothing: antialiased;
        }

        .font-serif { font-family: 'Playfair Display', serif; }

        /* Продвинутая анимация появления */
        .reveal {
          animation: reveal-scale 1.2s cubic-bezier(0.16, 1, 0.3, 1) forwards;
          opacity: 0;
          transform: translateY(40px) scale(0.98);
        }

        @keyframes reveal-scale {
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }

        .stagger-1 { animation-delay: 0.15s; }
        .stagger-2 { animation-delay: 0.3s; }

        html { scroll-behavior: smooth; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: #0d0d0f; }
        ::-webkit-scrollbar-thumb { background: rgba(255, 179, 217, 0.2); border-radius: 10px; }

        .project-card {
            transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1);
        }

        .project-card:hover {
            transform: translateY(-10px);
        }

        .project-card:hover .project-image {
          transform: scale(1.08);
        }

        .glass {
          background: rgba(13, 13, 15, 0.85);
          backdrop-filter: blur(15px);
          -webkit-backdrop-filter: blur(15px);
        }

        .aspect-w-4 { position: relative; padding-bottom: 75%; }
        .aspect-w-4 > * { position: absolute; height: 100%; width: 100%; top: 0; left: 0; }
        .aspect-square { position: relative; padding-bottom: 100%; }
        .aspect-square > * { position: absolute; height: 100%; width: 100%; top: 0; left: 0; }
      `}</style>

      {/* Header & Navigation */}
      <div className="fixed top-0 w-full z-50 flex flex-col">
        <header className={`px-6 md:px-12 py-5 glass border-b border-white border-opacity-5 transition-all duration-500 ${isScrolled ? 'py-4' : 'py-7'}`}>
          <div className="max-w-7xl mx-auto flex justify-between items-center">
            <div className="text-sm md:text-lg font-bold tracking-[0.2em] text-[#ffb3d9] uppercase">
              АЛЕКСАНДРА БЛАГОДАТСКИХ
            </div>

            <nav className="hidden lg:flex items-center gap-10 text-[10px] uppercase tracking-[0.2em] text-white text-opacity-40">
              <button onClick={() => scrollTo('projects')} className="hover:text-[#ffb3d9] transition-all">Проекты</button>
              <button onClick={() => scrollTo('about')} className="hover:text-[#ffb3d9] transition-all">Обо мне</button>
              <button onClick={() => scrollTo('contact')} className="hover:text-[#ffb3d9] transition-all">Контакты</button>
            </nav>

            <div className="flex gap-6 items-center">
              <a href="https://t.me/renraie" target="_blank" rel="noreferrer" className="text-white text-opacity-40 hover:text-[#ffb3d9] transition-all transform hover:scale-110">
                <Icon name="telegram"/>
              </a>
              <a href="tel:+79639960003" className="text-white text-opacity-40 hover:text-[#ffb3d9] transition-all transform hover:scale-110">
                <Icon name="phone"/>
              </a>
            </div>
          </div>
        </header>

        <div className="px-6 md:px-12 py-4 glass border-b border-white border-opacity-5">
          <div className="max-w-7xl mx-auto flex flex-wrap gap-2">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`px-4 py-1.5 rounded-full text-[10px] uppercase tracking-widest transition-all duration-300 border ${
                  filter === cat 
                  ? 'bg-[#ffb3d9] border-[#ffb3d9] text-[#2d1b24] shadow-[0_0_15px_rgba(255,179,217,0.2)]' 
                  : 'bg-white bg-opacity-5 border-white border-opacity-10 text-white text-opacity-40 hover:border-opacity-30'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Hero / About Section */}
      <section id="about" className="pt-80 pb-24 px-6 md:px-12">
        <div className="max-w-7xl mx-auto reveal">
          <h1 className="text-5xl md:text-[6.5rem] font-serif font-light tracking-tight mb-8 leading-[1.05] text-white">
            Учусь делать <span className="italic text-[#ffb3d9]">красивый</span> и понятный дизайн.
          </h1>
          <p className="max-w-2xl text-white text-opacity-40 text-xl font-light leading-relaxed stagger-1">
            Привет, я Александра. Изучаю айдентику, логотипы и веб-дизайн. 
            Здесь я собираю свои работы — от первых шагов в печатной графике до текущих учебных кейсов.
          </p>
        </div>
      </section>

      {/* Projects Section */}
      <main id="projects" className="max-w-7xl mx-auto px-6 md:px-12 pb-32">
        <div className="mb-24">
          <h2 className="text-[10px] uppercase tracking-[0.4em] text-white text-opacity-20 mb-10 reveal">Избранные проекты</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
            {filteredFeatured.map((project, index) => (
              <div key={project.id} className={`project-card group cursor-pointer reveal stagger-${(index % 2) + 1}`}>
                <div className="relative rounded-[2.5rem] overflow-hidden aspect-w-4 aspect-h-3 bg-[#161618] mb-8 border border-white border-opacity-5 shadow-2xl transition-all duration-700 group-hover:border-[#ffb3d9] group-hover:border-opacity-20">
                  <img src={project.img} alt={project.title} className="project-image w-full h-full object-cover transition-transform duration-1000 ease-out" />
                  <div className="absolute inset-0 bg-gradient-to-t from-[#0d0d0f] to-transparent opacity-0 group-hover:opacity-40 transition-opacity duration-500" />
                </div>
                <div className="flex justify-between items-end px-4">
                  <div>
                    <h3 className="text-2xl font-light mb-2 group-hover:text-[#ffb3d9] transition-colors">{project.title}</h3>
                    <p className="text-[10px] uppercase tracking-widest text-white text-opacity-30">{project.cat}</p>
                  </div>
                  <span className="text-[10px] font-mono text-white text-opacity-10">{project.year}</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Archive */}
        <div className="pt-10 border-t border-white border-opacity-5 flex flex-col items-center">
          <button 
              onClick={() => setShowArchive(!showArchive)}
              className="group relative px-10 py-4 bg-white bg-opacity-5 rounded-full text-[10px] uppercase tracking-[0.4em] text-white text-opacity-40 overflow-hidden transition-all duration-500"
          >
            <div className="absolute inset-0 bg-[#ffb3d9] opacity-0 group-hover:opacity-10 transition-opacity"></div>
            <span className="relative group-hover:text-[#ffb3d9] transition-colors">
                {showArchive ? '— Свернуть архив' : '+ Показать архив'}
            </span>
          </button>

          {showArchive && (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mt-16 w-full">
              {filteredArchive.map((project) => (
                <div key={project.id} className="group reveal">
                  <div className="relative rounded-3xl overflow-hidden aspect-square bg-[#161618] mb-5 border border-white border-opacity-5 transition-all group-hover:border-opacity-20 group-hover:shadow-lg">
                      <img src={project.img} alt={project.title} className="w-full h-full object-cover opacity-30 group-hover:opacity-100 transition-all duration-700 group-hover:scale-110" />
                  </div>
                  <h4 className="text-md font-light text-white text-opacity-60 mb-1 group-hover:text-white transition-colors">{project.title}</h4>
                  <p className="text-[9px] uppercase tracking-widest text-white text-opacity-20">{project.cat}</p>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      {/* Footer / Contact Section */}
      <footer id="contact" className="py-32 px-6 md:px-12 bg-[#0a0a0c] border-t border-white border-opacity-5">
        <div className="max-w-7xl mx-auto">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-20">
            <div className="reveal">
              <h2 className="text-5xl md:text-7xl font-serif mb-16 italic text-[#ffb3d9] leading-tight">Связаться со мной</h2>
              <div className="flex flex-col gap-10 stagger-1">
                <div>
                    <p className="text-[9px] uppercase tracking-[0.4em] text-white text-opacity-20 mb-4">Телефон</p>
                    <a href="tel:+79639960003" className="text-3xl md:text-5xl font-light hover:text-[#ffb3d9] transition-all inline-block">8 (963) 996-00-03</a>
                </div>
                <div>
                    <p className="text-[9px] uppercase tracking-[0.4em] text-white text-opacity-20 mb-4">Мессенджер</p>
                    <a href="https://t.me/renraie" target="_blank" rel="noreferrer" className="text-3xl md:text-5xl font-light hover:text-[#ffb3d9] transition-all inline-block">Telegram: @renraie</a>
                </div>
              </div>
            </div>

            <div className="flex flex-col items-end gap-6 reveal stagger-2">
                <div className="flex gap-4">
                    <div className="w-12 h-12 rounded-full border border-white border-opacity-5 flex items-center justify-center text-white text-opacity-20 hover:text-[#ffb3d9] hover:border-[#ffb3d9] hover:border-opacity-30 transition-all cursor-pointer font-serif italic">Be</div>
                    <div className="w-12 h-12 rounded-full border border-white border-opacity-5 flex items-center justify-center text-white text-opacity-20 hover:text-[#ffb3d9] hover:border-[#ffb3d9] hover:border-opacity-30 transition-all cursor-pointer font-serif italic">Ig</div>
                </div>
                <div className="text-[10px] uppercase tracking-[0.5em] text-white text-opacity-10 font-sans">
                  © 2024—2026 Alexandra Blagodatskikh
                </div>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;
